vector<int> Solution::earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
    int earliest = 1, latest = 1;
    for (int i = 2; i <= n; i <<= 1) {
        int mid = i >> 1;
        if (firstPlayer <= mid && secondPlayer > mid) {
            earliest = max(earliest, (firstPlayer + secondPlayer - 1) / 2 + 1);
            latest = max(latest, (firstPlayer + secondPlayer - 1) / 2 + 1);
        } else if (firstPlayer > mid && secondPlayer <= mid) {
            earliest = max(earliest, (firstPlayer + secondPlayer - 1) / 2 + 1);
            latest = max(latest, (firstPlayer + secondPlayer - 1) / 2 + 1);
        } else if (firstPlayer <= mid && secondPlayer <= mid) {
            earliest = max(earliest, (firstPlayer + secondPlayer - 1) / 2 + 1);
            latest = max(latest, (firstPlayer + secondPlayer - 1) / 2 + 1);
        } else if (firstPlayer > mid && secondPlayer > mid) {
            earliest = max(earliest, (firstPlayer + secondPlayer - i) / 2 + 1);
            latest = min(latest, (firstPlayer + secondPlayer - i) / 2 + 1);
        }
    }
    return {earliest, latest};
}
